import { useEffect, useState } from "react";
import PageHeader from "../components/PageHeader";
import { createMedication, getMedications } from "../services/api";

export default function MedicationPage() {
  const [items, setItems] = useState([]);
  const [form, setForm] = useState({ medicine_name: "", dosage: "", schedule: "", instructions: "", document: null });

  const load = async () => setItems(await getMedications());
  useEffect(() => { load(); }, []);

  const handleSubmit = async (event) => {
    event.preventDefault();
    await createMedication(form);
    setForm({ medicine_name: "", dosage: "", schedule: "", instructions: "", document: null });
    load();
  };

  return (
    <>
      <PageHeader title="Medication Management" description="Upload prescriptions, store schedules, and monitor reminder-ready entries in one dedicated workspace." />
      <div className="split-layout">
        <div className="panel">
          <form onSubmit={handleSubmit}>
            <div className="field"><label>Medicine Name</label><input value={form.medicine_name} onChange={(e) => setForm({ ...form, medicine_name: e.target.value })} /></div>
            <div className="form-grid">
              <div className="field"><label>Dosage</label><input value={form.dosage} onChange={(e) => setForm({ ...form, dosage: e.target.value })} /></div>
              <div className="field"><label>Schedule</label><input value={form.schedule} onChange={(e) => setForm({ ...form, schedule: e.target.value })} /></div>
            </div>
            <div className="field"><label>Instructions</label><textarea value={form.instructions} onChange={(e) => setForm({ ...form, instructions: e.target.value })} /></div>
            <div className="field"><label>Upload Prescription PDF</label><input type="file" accept="application/pdf" onChange={(e) => setForm({ ...form, document: e.target.files?.[0] || null })} /></div>
            <button className="btn btn-primary" type="submit">Save Medication</button>
          </form>
        </div>
        <div className="panel">
          <h3 className="section-title">Medication Schedule</h3>
          <div className="summary-list">
            {items.map((item) => <div className="summary-item" key={item.id}><strong>{item.medicine_name}</strong><div>{item.dosage || "No dosage specified"}</div><div>{item.schedule}</div><span className="pill">{item.reminder_email_sent ? "Reminder sent" : "Pending"}</span></div>)}
          </div>
        </div>
      </div>
    </>
  );
}
